/**
 * ThreeLightSetup — Script 14: Event Testimonials
 * 3-light positioning guide for filming testimonials on location.
 */
import React from "react";
import {
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { COLOR, FONT_WEIGHT, SPRING } from "./brand";
import { GraphicWrapper } from "./GraphicWrapper";

const LIGHTS = [
  {
    num:    "①",
    label:  "KEY LIGHT",
    detail: "45° front — tripod at head height. Primary illumination.",
  },
  {
    num:    "②",
    label:  "FILL LIGHT",
    detail: "90° opposite side — softens shadows from the key light.",
  },
  {
    num:    "③",
    label:  "BACK LIGHT",
    detail: "45° behind the speaker — separates them from the background.",
  },
];

const ROW_DELAYS = [8, 38, 68];

const LightRow: React.FC<{ light: typeof LIGHTS[number]; delay: number }> = ({ light, delay }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const slideX = spring({
    frame: Math.max(0, frame - delay),
    fps,
    from: -40,
    to: 0,
    config: SPRING.smooth,
  });

  const rowOp = interpolate(frame, [delay, delay + 14], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  return (
    <div style={{
      display: "flex",
      alignItems: "center",
      gap: 24,
      opacity: rowOp,
      transform: `translateX(${slideX}px)`,
    }}>

      {/* Number badge */}
      <span style={{
        fontSize: 52,
        fontWeight: FONT_WEIGHT.extraBold,
        color: COLOR.ringSecondary,
        lineHeight: 1,
        minWidth: 52,
        textAlign: "center",
      }}>
        {light.num}
      </span>

      {/* Label */}
      <span style={{
        fontSize: 26,
        fontWeight: FONT_WEIGHT.extraBold,
        color: COLOR.ringPrimary,
        letterSpacing: "0.08em",
        minWidth: 200,
      }}>
        {light.label}
      </span>

      {/* Arrow */}
      <span style={{
        fontSize: 20,
        color: COLOR.textSecondary,
        fontWeight: FONT_WEIGHT.extraBold,
      }}>
        →
      </span>

      {/* Detail */}
      <span style={{
        fontSize: 21,
        fontWeight: FONT_WEIGHT.extraBold,
        color: COLOR.textMuted,
        letterSpacing: "0.02em",
        lineHeight: 1.35,
        maxWidth: 420,
      }}>
        {light.detail}
      </span>

    </div>
  );
};

export const ThreeLightSetup: React.FC = () => {
  const frame = useCurrentFrame();

  const headerOp = interpolate(frame, [0, 10], [0, 1], { extrapolateRight: "clamp" });

  return (
    <GraphicWrapper>
      <div style={{ display: "flex", flexDirection: "column", gap: 18, alignItems: "flex-start" }}>

        {/* Header */}
        <div style={{ opacity: headerOp, marginBottom: 10 }}>
          <span style={{
            fontSize: 13,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textSecondary,
            letterSpacing: "0.22em",
            textTransform: "uppercase",
          }}>
            3-LIGHT SETUP — POCKET-SIZED RGB LIGHTS
          </span>
        </div>

        {LIGHTS.map((light, i) => (
          <LightRow key={i} light={light} delay={ROW_DELAYS[i]} />
        ))}

      </div>
    </GraphicWrapper>
  );
};

/**
 * Brand Tokens — single source of truth for all motion graphics.
 * Update here and every composition picks it up automatically.
 */

// ── Colours ───────────────────────────────────────────────────────────────
export const COLOR = {
  // Background gradient (radial, centre → edge)
  bgCenter:  "#e0e1dd",
  bgMid:     "#6b6b6b",
  bgEdge:    "#222222",

  // Ring accents
  ringPrimary:   "#415a77",   // steel blue  — main data ring
  ringSecondary: "#c2a46d",   // warm gold   — supporting ring
  ringTrack:     "rgba(0,0,0,0.08)",

  // Typography
  textPrimary:   "#1D1D1F",
  textSecondary: "rgba(29,29,31,0.45)",
  textMuted:     "rgba(29,29,31,0.6)",
  textAccent:    "#415a77",   // matches ringPrimary

  // Glow
  glowPrimary: "rgba(65,90,119,0.7)",
} as const;

// ── Background gradient string ─────────────────────────────────────────────
export const BG_GRADIENT =
  `radial-gradient(ellipse at 50% 50%, ${COLOR.bgCenter} 0%, ${COLOR.bgCenter} 16%, ${COLOR.bgMid} 60%, ${COLOR.bgEdge} 100%)`;

// ── Typography ─────────────────────────────────────────────────────────────
export const FONT_WEIGHT = {
  regular:   400,
  semibold:  600,
  bold:      700,
  extraBold: 800,  // ← brand standard — use this for all display text
} as const;

// ── Animation defaults ─────────────────────────────────────────────────────
export const SPRING = {
  snappy:  { damping: 15, stiffness: 220, mass: 1 },
  bouncy:  { damping: 12, stiffness: 280, mass: 0.8 },
  smooth:  { damping: 14, stiffness: 200, mass: 1 },
} as const;

export const DURATION = {
  short:    3,   // seconds — quick stat/callout graphic
  medium:   8,   // seconds — explanation graphic
  long:     15,  // seconds — full timeline breakdown
} as const;

// ── SVG ring geometry ──────────────────────────────────────────────────────
export const RING = {
  r:           78,
  strokeWidth: 34,
  get C()      { return 2 * Math.PI * this.r; },
} as const;

