        num="①" label="KEY LIGHT" sub="45° FRONT"
        color={SC.key} textColor="#fff"
        x={425} headY={390}
        labelX={382} labelAnchor="end"
        showBeam op={keyOp} sc={keySc} beamOp={keyBeam} labelOp={keyLbl}
        frame={frame}
      />

