              fontWeight={800}
              fill={COLOR.textPrimary}
              opacity={0.75}
              fontFamily="Montserrat, sans-serif"
              letterSpacing={1}
            >
              POOR VIDEO
            </text>

            {/* Track */}
            <rect
              x={BAR_X} y={0}
              width={BAR_MAX_W} height={BAR_H}
