                fontSize={22}
                fontWeight={800}
                fill={COLOR.ringSecondary}
                fontFamily="Montserrat, sans-serif"
                dominantBaseline="middle"
              >
                HIGH
              </text>
              <text
                x={BAR_X + videoBarW + 16}
                y={BAR_H / 2 + 16}
                fontSize={11}
                fontWeight={800}
                fill={COLOR.textMuted}
                fontFamily="Montserrat, sans-serif"
                letterSpacing={1}
              >
                TOLERANCE
              </text>
            </g>
          </g>

          {/* ── Row 2: AUDIO ───────────────────────────────────────────── */}
          <g transform={`translate(0, 148)`}>
            {/* Category label */}
            <text
              x={LABEL_X}
              y={BAR_H / 2 + 6}
              fontSize={15}
              fontWeight={800}
              fill={COLOR.textPrimary}
              opacity={0.75}
              fontFamily="Montserrat, sans-serif"
              letterSpacing={1}
            >
              POOR AUDIO
            </text>

            {/* Track */}
            <rect
