/**
 * NinetyOnePercent — Script 14: Event Testimonials
 * Stat: "91% of B2B buyers say result-driven stories are the primary factor
 * in their purchasing decisions." — Wyzowl 2026
 */
import React from "react";
import {
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { COLOR, FONT_WEIGHT, SPRING } from "./brand";
import { GraphicWrapper } from "./GraphicWrapper";

export const NinetyOnePercent: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Hero number
  const heroSpring = spring({ frame, fps, from: 0, to: 1, config: SPRING.bouncy });
  const heroScale  = interpolate(heroSpring, [0, 0.65, 1], [0.6, 1.1, 1]);
  const heroOp     = interpolate(frame, [0, 10], [0, 1], { extrapolateRight: "clamp" });

  // Sub-line
  const subOp = interpolate(frame, [14, 26], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
  const subY  = spring({ frame: Math.max(0, frame - 14), fps, from: 12, to: 0, config: SPRING.smooth });

  // Source label
  const srcOp = interpolate(frame, [30, 42], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

  return (
    <GraphicWrapper>
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 18 }}>

        {/* 91% */}
        <div style={{ opacity: heroOp, transform: `scale(${heroScale})` }}>
          <span style={{
            fontSize: 220,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.ringSecondary,
            letterSpacing: "-0.06em",
            lineHeight: 1,
            display: "block",
            textAlign: "center",
          }}>
            91%
          </span>
        </div>

        {/* Sub-line */}
        <div style={{ opacity: subOp, transform: `translateY(${subY}px)`, textAlign: "center", maxWidth: 720 }}>
          <span style={{
            fontSize: 24,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textPrimary,
            letterSpacing: "0.04em",
            textTransform: "uppercase",
            lineHeight: 1.35,
          }}>
            OF B2B BUYERS SAY RESULT-DRIVEN STORIES ARE{"\n"}THE PRIMARY FACTOR IN THEIR PURCHASING DECISIONS
          </span>
        </div>

        {/* Source */}
        <div style={{ opacity: srcOp }}>
          <span style={{
            fontSize: 13,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textSecondary,
            letterSpacing: "0.22em",
            textTransform: "uppercase",
          }}>
            WYZOWL 2026
          </span>
        </div>

      </div>
    </GraphicWrapper>
  );
};

/**
 * VideographerCost — Script 14: Event Testimonials
 * Cost callout: count-up to £2,000, then "+" bounces in.
 */
import React from "react";
import {
  Easing,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { COLOR, FONT_WEIGHT, SPRING } from "./brand";
import { GraphicWrapper } from "./GraphicWrapper";

const COUNT_START = 8;
const COUNT_END   = 54; // 46 frames ≈ 1.5 s count-up

export const VideographerCost: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // ── Label ─────────────────────────────────────────────────────────────────
  const labelOp = interpolate(frame, [0, 10], [0, 1], { extrapolateRight: "clamp" });

  // ── Hero container — scale-up on entry ────────────────────────────────────
  const heroSpring = spring({ frame: Math.max(0, frame - COUNT_START), fps, from: 0, to: 1, config: SPRING.bouncy });
  const heroScale  = interpolate(heroSpring, [0, 0.65, 1], [0.6, 1.1, 1]);
  const heroOp     = interpolate(frame, [COUNT_START, COUNT_START + 10], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  // ── Count-up 0 → 2000 ─────────────────────────────────────────────────────
  const countValue = Math.round(
    interpolate(frame, [COUNT_START, COUNT_END], [0, 2000], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
      easing: Easing.out(Easing.cubic),
    })
  );

  // Format with comma: £2,000
  const formatted =
    countValue >= 1000
      ? `£${Math.floor(countValue / 1000)},${String(countValue % 1000).padStart(3, "0")}`
      : `£${countValue}`;

  // ── "+" bounces in after count lands ──────────────────────────────────────
  const plusSpring = spring({ frame: Math.max(0, frame - COUNT_END), fps, from: 0, to: 1, config: SPRING.bouncy });
  const plusScale  = interpolate(plusSpring, [0, 0.65, 1], [0, 1.3, 1]);
  const plusOp     = interpolate(frame, [COUNT_END, COUNT_END + 6], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  // ── Sub-line fades up after "+" lands ─────────────────────────────────────
  const subDelay = COUNT_END + 10;
  const subOp = interpolate(frame, [subDelay, subDelay + 12], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  const subY = spring({ frame: Math.max(0, frame - subDelay), fps, from: 12, to: 0, config: SPRING.smooth });

  return (
    <GraphicWrapper>
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 14 }}>

        {/* Label */}
        <div style={{ opacity: labelOp }}>
          <span style={{
            fontSize: 13,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textSecondary,
            letterSpacing: "0.22em",
            textTransform: "uppercase",
          }}>
            HIRING A VIDEOGRAPHER
          </span>
        </div>

        {/* Number + plus — inline so they sit flush */}
        <div style={{
          opacity: heroOp,
          transform: `scale(${heroScale})`,
          display: "flex",
          alignItems: "baseline",
          lineHeight: 1,
        }}>
          {/* Counting number */}
          <span style={{
            fontSize: 200,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.ringSecondary,
            letterSpacing: "-0.04em",
            lineHeight: 1,
          }}>
            {formatted}
          </span>

          {/* "+" bounces in separately */}
          <span style={{
            fontSize: 200,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.ringSecondary,
            letterSpacing: "-0.04em",
            lineHeight: 1,
            opacity: plusOp,
            transform: `scale(${plusScale})`,
            display: "inline-block",
            transformOrigin: "left center",
          }}>
            +
          </span>
        </div>

        {/* Sub-line */}
        <div style={{ opacity: subOp, transform: `translateY(${subY}px)`, textAlign: "center" }}>
          <span style={{
            fontSize: 22,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textMuted,
            letterSpacing: "0.04em",
            textTransform: "uppercase",
          }}>
            YOU CAN STILL GET GREAT RESULTS WITHOUT ONE
          </span>
        </div>

      </div>
    </GraphicWrapper>
  );
};

/**
 * PSRFramework — Script 14: Event Testimonials
 * The Problem / Shift / Result framework for structured testimonials.
 */
import React from "react";
import {
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { COLOR, FONT_WEIGHT, SPRING } from "./brand";
import { GraphicWrapper } from "./GraphicWrapper";

const STEPS = [
  {
    letter: "P",
    label:  "PROBLEM",
    detail: "What specific hurdle was your firm facing before you arrived?",
  },
  {
    letter: "S",
    label:  "SHIFT",
    detail: "What happened at the forum that changed that?",
  },
  {
    letter: "R",
    label:  "RESULT",
    detail: "What was your measurable outcome?",
  },
];

const ROW_DELAYS = [8, 40, 72];

const StepRow: React.FC<{ step: typeof STEPS[number]; delay: number }> = ({ step, delay }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const slideX = spring({
    frame: Math.max(0, frame - delay),
    fps,
    from: -44,
    to: 0,
    config: SPRING.smooth,
  });

  const rowOp = interpolate(frame, [delay, delay + 14], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  return (
    <div style={{
      display: "flex",
      alignItems: "center",
      gap: 28,
      opacity: rowOp,
      transform: `translateX(${slideX}px)`,
    }}>

      {/* Letter badge */}
      <span style={{
        fontSize: 72,
        fontWeight: FONT_WEIGHT.extraBold,
        color: COLOR.ringSecondary,
        lineHeight: 1,
        minWidth: 60,
        textAlign: "center",
      }}>
        {step.letter}
      </span>

      {/* Divider */}
      <div style={{
