/**
 * NinetyOnePercent — Script 14: Event Testimonials
 * Arc ring fills to 91% with count-up inside. Description to the right.
 */
import React from "react";
import { Easing, interpolate, spring, useCurrentFrame, useVideoConfig } from "remotion";
import { COLOR, FONT_WEIGHT, RING, SPRING } from "./brand";
import { GraphicWrapper } from "./GraphicWrapper";

const R  = 130;
const SW = 24;
const C  = 2 * Math.PI * R;   // ≈ 817

export const NinetyOnePercent: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // ── Arc fills to 91% ──────────────────────────────────────────────────────
  const arcProgress = interpolate(frame, [0, 42], [0, 0.91], {
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });
  const dashOffset = C * (1 - arcProgress);

  // ── Number counts up inside ring ──────────────────────────────────────────
  const numValue = Math.round(
    interpolate(frame, [0, 38], [0, 91], {
      extrapolateRight: "clamp",
      easing: Easing.out(Easing.cubic),
    })
  );

  // ── Right text block ──────────────────────────────────────────────────────
  const subOp = interpolate(frame, [18, 30], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
  const subY  = spring({ frame: Math.max(0, frame - 18), fps, from: 12, to: 0, config: SPRING.smooth });
  const srcOp = interpolate(frame, [34, 46], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

  const SVG_SIZE = (R + SW) * 2 + 16;  // 308

  return (
    <GraphicWrapper>
      <div style={{ display: "flex", alignItems: "center", gap: 72 }}>

        {/* ── Arc ring ── */}
        <svg width={SVG_SIZE} height={SVG_SIZE} viewBox={`0 0 ${SVG_SIZE} ${SVG_SIZE}`}>
          <g transform={`translate(${SVG_SIZE / 2}, ${SVG_SIZE / 2}) rotate(-90)`}>
            {/* Track */}
            <circle
              r={R} cx={0} cy={0}
              fill="none"
              stroke="rgba(29,29,31,0.08)"
              strokeWidth={SW}
            />
            {/* Filled arc */}
            <circle
              r={R} cx={0} cy={0}
              fill="none"
              stroke={COLOR.ringSecondary}
              strokeWidth={SW}
              strokeDasharray={C}
              strokeDashoffset={dashOffset}
              strokeLinecap="round"
            />
          </g>

          {/* Number inside ring */}
          <text
            x={SVG_SIZE / 2} y={SVG_SIZE / 2}
            textAnchor="middle"
            dominantBaseline="middle"
            fontSize={74}
            fontWeight={800}
            fill={COLOR.ringSecondary}
            fontFamily="Montserrat, sans-serif"
            letterSpacing="-2"
          >
            {numValue}%
          </text>
        </svg>

        {/* ── Description block ── */}
        <div style={{ display: "flex", flexDirection: "column", gap: 14, maxWidth: 520 }}>

          <div style={{ opacity: subOp, transform: `translateY(${subY}px)` }}>
            <span style={{
              fontSize: 26,
              fontWeight: FONT_WEIGHT.extraBold,
              color: COLOR.textPrimary,
              letterSpacing: "0.04em",
              textTransform: "uppercase",
              lineHeight: 1.4,
              display: "block",
            }}>
              OF B2B BUYERS SAY RESULT-DRIVEN STORIES ARE THE PRIMARY FACTOR IN THEIR PURCHASING DECISIONS
            </span>
          </div>

          <div style={{ opacity: srcOp }}>
            <span style={{
              fontSize: 13,
              fontWeight: FONT_WEIGHT.extraBold,
              color: COLOR.textSecondary,
              letterSpacing: "0.22em",
              textTransform: "uppercase",
            }}>
              WYZOWL 2026
            </span>
          </div>

        </div>
      </div>
    </GraphicWrapper>
  );
};

/**
 * VideographerCost — Script 14: Event Testimonials
 * Count-up to £2,000+ with fill bar growing in sync.
 */
import React from "react";
import { Easing, interpolate, spring, useCurrentFrame, useVideoConfig } from "remotion";
import { COLOR, FONT_WEIGHT, SPRING } from "./brand";
import { GraphicWrapper } from "./GraphicWrapper";

const COUNT_START = 8;
const COUNT_END   = 54;
const BAR_W       = 620;

export const VideographerCost: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // ── Label ─────────────────────────────────────────────────────────────────
  const labelOp = interpolate(frame, [0, 10], [0, 1], { extrapolateRight: "clamp" });

  // ── Hero container ─────────────────────────────────────────────────────────
  const heroSpring = spring({ frame: Math.max(0, frame - COUNT_START), fps, from: 0, to: 1, config: SPRING.bouncy });
  const heroScale  = interpolate(heroSpring, [0, 0.65, 1], [0.6, 1.1, 1]);
  const heroOp     = interpolate(frame, [COUNT_START, COUNT_START + 10], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp",
  });

  // ── Count-up 0 → 2000 ─────────────────────────────────────────────────────
  const countValue = Math.round(
    interpolate(frame, [COUNT_START, COUNT_END], [0, 2000], {
      extrapolateLeft: "clamp", extrapolateRight: "clamp",
      easing: Easing.out(Easing.cubic),
    })
  );
  const formatted =
    countValue >= 1000
      ? `£${Math.floor(countValue / 1000)},${String(countValue % 1000).padStart(3, "0")}`
      : `£${countValue}`;

  // ── "+" bounces in after count lands ──────────────────────────────────────
  const plusSpring = spring({ frame: Math.max(0, frame - COUNT_END), fps, from: 0, to: 1, config: SPRING.bouncy });
  const plusScale  = interpolate(plusSpring, [0, 0.65, 1], [0, 1.3, 1]);
  const plusOp     = interpolate(frame, [COUNT_END, COUNT_END + 6], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp",
  });

  // ── Progress bar fills in sync with count ─────────────────────────────────
  const barFill = interpolate(frame, [COUNT_START, COUNT_END], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });
  const barOp = interpolate(frame, [COUNT_START, COUNT_START + 8], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp",
  });

  // ── Sub-line fades up after "+" lands ─────────────────────────────────────
  const subDelay = COUNT_END + 10;
  const subOp = interpolate(frame, [subDelay, subDelay + 12], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp",
  });
  const subY = spring({ frame: Math.max(0, frame - subDelay), fps, from: 12, to: 0, config: SPRING.smooth });

  return (
    <GraphicWrapper>
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 14 }}>

        {/* Label */}
        <div style={{ opacity: labelOp }}>
          <span style={{
            fontSize: 13,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textSecondary,
            letterSpacing: "0.22em",
            textTransform: "uppercase",
          }}>
            HIRING A VIDEOGRAPHER
          </span>
        </div>

        {/* Number + plus */}
        <div style={{
          opacity: heroOp,
          transform: `scale(${heroScale})`,
          display: "flex",
          alignItems: "baseline",
          lineHeight: 1,
        }}>
          <span style={{
            fontSize: 200,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.ringSecondary,
            letterSpacing: "-0.04em",
            lineHeight: 1,
          }}>
            {formatted}
          </span>
          <span style={{
            fontSize: 200,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.ringSecondary,
            letterSpacing: "-0.04em",
            lineHeight: 1,
            opacity: plusOp,
            transform: `scale(${plusScale})`,
            display: "inline-block",
            transformOrigin: "left center",
          }}>
            +
          </span>
        </div>

        {/* Progress bar */}
        <div style={{ opacity: barOp, width: BAR_W, marginTop: -8 }}>
          {/* Track */}
          <div style={{
            width: BAR_W,
            height: 6,
            borderRadius: 3,
            background: "rgba(29,29,31,0.08)",
            position: "relative",
            overflow: "hidden",
          }}>
            {/* Fill */}
            <div style={{
              position: "absolute",
              left: 0, top: 0, bottom: 0,
              width: barFill * BAR_W,
              background: COLOR.ringSecondary,
              borderRadius: 3,
            }} />
          </div>
        </div>

        {/* Sub-line */}
        <div style={{ opacity: subOp, transform: `translateY(${subY}px)`, textAlign: "center", marginTop: 8 }}>
          <span style={{
            fontSize: 22,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textMuted,
            letterSpacing: "0.04em",
            textTransform: "uppercase",
          }}>
            YOU CAN STILL GET GREAT RESULTS WITHOUT ONE
          </span>
        </div>

      </div>
    </GraphicWrapper>
  );
};

/**
 * PSRFramework — Script 14: Event Testimonials
 * 3-card horizontal flow: Problem → Shift → Result
 */
import React from "react";
import { Easing, interpolate, spring, useCurrentFrame, useVideoConfig } from "remotion";
import { COLOR, FONT_WEIGHT, SPRING } from "./brand";
import { GraphicWrapper } from "./GraphicWrapper";

const STEPS = [
  {
    letter: "P",
    label:  "PROBLEM",
    detail: "What specific hurdle was your firm facing before you arrived?",
    color:  COLOR.ringPrimary,
    delay:  8,
  },
  {
    letter: "S",
    label:  "SHIFT",
    detail: "What happened at the forum that changed that?",
    color:  COLOR.ringSecondary,
    delay:  40,
  },
  {
    letter: "R",
    label:  "RESULT",
    detail: "What was your measurable outcome?",
    color:  COLOR.ringPrimary,
    delay:  72,
  },
];

const CARD_W = 380;
const CARD_H = 210;

const Card: React.FC<{ step: typeof STEPS[number] }> = ({ step }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const sc = spring({
    frame: Math.max(0, frame - step.delay),
    fps,
    from: 0.82,
    to: 1,
    config: SPRING.snappy,
  });
  const op = interpolate(frame, [step.delay, step.delay + 16], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp",
  });
  const detailOp = interpolate(frame, [step.delay + 16, step.delay + 28], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp",
  });

  return (
    <div style={{
      opacity:       op,
      transform:     `scale(${sc})`,
      width:         CARD_W,
      height:        CARD_H,
      borderRadius:  18,
      background:    `rgba(${step.color === COLOR.ringSecondary ? "194,164,109" : "65,90,119"},0.08)`,
      border:        `1.5px solid ${step.color}30`,
      padding:       "28px 30px",
      display:       "flex",
      flexDirection: "column",
      gap:           10,
      boxSizing:     "border-box",
    }}>

      {/* Large letter */}
      <span style={{
        fontSize:      64,
        fontWeight:    FONT_WEIGHT.extraBold,
        color:         step.color,
        lineHeight:    1,
        letterSpacing: "-0.02em",
      }}>
        {step.letter}
      </span>

      {/* Label */}
      <span style={{
        fontSize:      16,
        fontWeight:    FONT_WEIGHT.extraBold,
        color:         step.color,
        letterSpacing: "0.14em",
        textTransform: "uppercase",
      }}>
        {step.label}
      </span>

      {/* Detail */}
      <span style={{
        fontSize:   15,
        fontWeight: FONT_WEIGHT.extraBold,
        color:      COLOR.textMuted,
        lineHeight: 1.45,
        opacity:    detailOp,
      }}>
        {step.detail}
      </span>

    </div>
  );
};

// Arrow that draws in between cards
const Arrow: React.FC<{ delay: number }> = ({ delay }) => {
  const frame = useCurrentFrame();
  const progress = interpolate(frame, [delay, delay + 18], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });

  return (
    <div style={{
      display:    "flex",
      alignItems: "center",
      opacity:    progress,
      marginTop:  -(CARD_H / 2 - 14),  // align to letter centre
    }}>
      <svg width={56} height={24} viewBox="0 0 56 24">
        <line
          x1={0} y1={12}
          x2={progress * 40} y2={12}
          stroke={COLOR.textSecondary}
          strokeWidth={1.5}
          opacity={0.5}
        />
        {progress > 0.7 && (
          <polyline
            points="38,6 48,12 38,18"
            fill="none"
            stroke={COLOR.textSecondary}
            strokeWidth={1.5}
            opacity={(progress - 0.7) / 0.3 * 0.5}
          />
        )}
      </svg>
    </div>
  );
};

export const PSRFramework: React.FC = () => {
  const frame = useCurrentFrame();
  const headerOp = interpolate(frame, [0, 10], [0, 1], { extrapolateRight: "clamp" });

  return (
    <GraphicWrapper>
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 28 }}>

        {/* Header */}
        <div style={{ opacity: headerOp }}>
          <span style={{
            fontSize:      13,
            fontWeight:    FONT_WEIGHT.extraBold,
            color:         COLOR.textSecondary,
            letterSpacing: "0.22em",
            textTransform: "uppercase",
          }}>
            THE PSR FRAMEWORK — STRUCTURED TESTIMONIALS
          </span>
        </div>

        {/* 3-card row */}
        <div style={{ display: "flex", alignItems: "flex-start", gap: 0 }}>
          {STEPS.map((step, i) => (
            <React.Fragment key={i}>
              <Card step={step} />
              {i < STEPS.length - 1 && (
                <Arrow delay={STEPS[i + 1].delay - 10} />
              )}
            </React.Fragment>
          ))}
        </div>

      </div>
    </GraphicWrapper>
  );
};

/**
 * RiskMitigator — Script 14: Event Testimonials
 * Solid circle badges, vertical timeline connector, stagger reveal.
 */
