          flexShrink:      0,
        }}>
          <span style={{
            fontSize:   24,
            fontWeight: FONT_WEIGHT.extraBold,
            color:      "#fff",
            lineHeight: 1,
          }}>
            {point.num}
          </span>
        </div>

        {/* Vertical connector (not shown on last item) */}
        {!isLast && (
          <div style={{
            width:        2,
            height:       ROW_HEIGHT - BADGE_SIZE / 2,
            background:   `rgba(194,164,109,${lineProgress * 0.35})`,
            borderRadius: 1,
            marginTop:    4,
          }} />
        )}
      </div>

      {/* Right: text content */}
      <div style={{
        opacity:   rowOp,
        transform: `translateX(${slideX}px)`,
        paddingTop: 10,
        paddingBottom: isLast ? 0 : ROW_HEIGHT - BADGE_SIZE,
      }}>
        <span style={{
          fontSize:      26,
          fontWeight:    FONT_WEIGHT.extraBold,
          color:         COLOR.ringPrimary,
          letterSpacing: "0.08em",
          display:       "block",
          marginBottom:  6,
        }}>
          {point.label}
        </span>
        <span style={{
          fontSize:   20,
          fontWeight: FONT_WEIGHT.extraBold,
          color:      COLOR.textMuted,
          lineHeight: 1.4,
        }}>
          {point.detail}
        </span>
      </div>

    </div>
  );
};

