          </span>
        </div>
      </div>

      {/* Label */}
      <span style={{
        fontSize:      26,
        fontWeight:    FONT_WEIGHT.extraBold,
        color:         light.glowColor === "#f5f5f5" ? COLOR.textPrimary : light.glowColor,
