        minWidth:      200,
      }}>
        {light.label}
      </span>

      {/* Arrow */}
      <span style={{
        fontSize:   20,
        color:      COLOR.textSecondary,
        fontWeight: FONT_WEIGHT.extraBold,
      }}>
        →
      </span>

      {/* Detail */}
      <span style={{
        fontSize:   21,
        fontWeight: FONT_WEIGHT.extraBold,
        color:      COLOR.textMuted,
        lineHeight: 1.35,
        maxWidth:   420,
      }}>
        {light.detail}
